import React, { useEffect, useState } from 'react';
import { GlobalSwgSelector } from '../../assets/icons/global/GlobalSwgSelector';
import Select, { useStateManager } from 'react-select'
import s from './header.module.scss';

interface Props {
  
}

export const Header = (props: Props) => {
  const options = [
    { value: 'city-1', label: 'Алматы' },
    { value: 'city-2', label: 'Нур-Султан' },
    { value: 'city-3', label: 'Караганда' },
  ];

const [theme, setTheme] = useState('light');
const colourStyles = {
  control: (styles: any) => ({
    ...styles,
    backgroundColor:
  theme === 'dark' ? '#4f4f4f' : 'rgba(71, 147, 255, 0.2)',
    width: '194px',
    height: '37px',
    border: 'none',
    borderRadius: '10px',
    zIndex: 100,
  }),
  singleValue: (styles: any) => ({
    ...styles,
    color: theme === 'dark' ? '#fff' : '#000',
  }),
}




function changeTheme() {
  setTheme(theme === 'light' ? 'dark' : 'light');

}

  useEffect(() => {

    const root = document.querySelector(':root') as HTMLElement;

    const components = ['components-background','card-background','card-shadow','text-color',];

    components.forEach((component) => {
      root.style.setProperty(
        `--${component}-default`,
        `var(--${component}-${theme})`
      );
    });

    root.style.setProperty(
      '--body-background-default',`var(--body-background-${theme})`)

  }, [theme])
  return <header className={s.header}>
      <div className={s.wrapper}>
          <div className={s.logo}><GlobalSwgSelector id='header-logo'/></div>
          <div className={s.title}>Погода</div>
      </div>
      <div className={s.wrapper}> 
      <div className={s.change_theme} onClick={changeTheme}> <GlobalSwgSelector id="change-theme"/>
        </div> 
        <Select defaultValue={options[0]} styles={colourStyles} options={options} />
        </div>
  </header>
};
